#!/usr/bin/env node
/**
 * RobCo Persistence Audit — tests/robco-diagnostics.js
 *
 * AUTO-DISCOVERS every field in state.js and verifies it is handled by:
 *   - autoImportState() in api.js  (AI sync, file import, cloud pull)
 *   - exportSaveFile()  in state.js (export envelope)
 *   - saveCurrentToCloud() in cloud.js   (cloud push)
 *   - handleFileUpload()   in ui-saves.js (file import)
 *
 * If a new field is added to `state` but NOT wired into autoImportState(),
 * this script will exit with code 1 and name the missing field.
 *
 * Run:       node tests/robco-diagnostics.js
 * Auto-run:  install as .git/hooks/pre-commit  (see README at bottom)
 *
 * Requires:  Node.js (any version). Zero npm dependencies.
 */

'use strict';
const fs = require('fs');
const path = require('path');

const ROOT = path.join(__dirname, '..');

// ── Terminal helpers ───────────────────────────────────────────
let passed = 0,
  failed = 0;
// Promises any suite needs resolved before RESULTS prints/exits (the runner
// body below is otherwise fully synchronous CommonJS — no top-level await).
// Suite 137.6's confirmAction() behavioral proof is the sole current user.
const _pendingAsync = [];
const green = s => `\x1b[32m${s}\x1b[0m`;
const red = s => `\x1b[31m${s}\x1b[0m`;
const dim = s => `\x1b[2m${s}\x1b[0m`;

function pass(msg) {
  console.log(green('  ✓') + dim(`  ${msg}`));
  passed++;
}
function fail(msg) {
  console.error(red('  ✗') + `  ${msg}`);
  failed++;
}
function assert(ok, msg) {
  ok ? pass(msg) : fail(msg);
}

// ── Static-guard table driver (token-audit #11) ────────────────
// Collapses the repetitive string-match guards into compact data tables.
// Each row: [pattern, msg] or [pattern, msg, NEG].
//   pattern — a RegExp → matched with pattern.test(src); a string → src.includes(pattern).
//   NEG     — invert polarity: assert the pattern is ABSENT.
// Behaviour is identical to the longhand assert(src.includes(...)) /
// assert(/re/.test(src)) forms it replaces, so runner output is unchanged.
const NEG = true;
function guards(src, rows) {
  for (const row of rows) {
    const pattern = row[0];
    const present = pattern instanceof RegExp ? pattern.test(src) : src.includes(pattern);
    assert(row[2] ? !present : present, row[1]);
  }
}
function header(title) {
  console.log(`\n── ${title} ${'─'.repeat(Math.max(0, 50 - title.length))}`);
}

// ── js/ subfolder resolver (2.8.5 U-A2) ─────────────────────────
// The reorg moved every js/*.js file into one of these subfolders. Rather
// than rewriting every readFile('js/<name>.js') call site across both
// runners, readFile() resolves a legacy flat 'js/<name>.js' path against
// the real on-disk location transparently — same call signature, same
// return value, same failure behavior for a name that doesn't exist
// anywhere (e.g. the sanctioned MUST-NOT-EXIST 'js/ui.js' probe still
// fails exactly as before). This mirrors readGroup's own "keep the call
// signature, resolve internally" precedent below.
const JS_SUBFOLDERS = ['data', 'core', 'ui', 'services', 'dev'];

// Recursively lists every js/<subfolder>/*.js file (js/vendor/ deliberately
// excluded — it's a separate, manually-curated precache allowlist, same
// scope js/ 's own flat readdirSync had pre-reorg since 'vendor' is a
// directory name, never a '.js' file). Returns {sub, name, rel} objects,
// rel being the 'sub/name.js' path used to build './js/'+rel entries.
// Any full-repo js-file scan (Suites 49, 212, 216, 220, ...) must walk
// subfolders like this, or it silently scans zero files post-reorg — an
// empty-corpus guard can vacuously pass OR spuriously fail depending on
// what it asserts, either way the exact class of regression Protocol 42
// requires fixing on discovery.
function allJsFiles(opts = {}) {
  const exclude = new Set(opts.exclude || []);
  const out = [];
  for (const sub of JS_SUBFOLDERS) {
    const subDir = path.join(ROOT, 'js', sub);
    if (!fs.existsSync(subDir)) continue;
    for (const f of fs.readdirSync(subDir)) {
      if (f.endsWith('.js') && !exclude.has(f)) out.push({ sub, name: f, rel: `${sub}/${f}` });
    }
  }
  return out;
}

let _jsLocationCache = null;
function _jsFileLocation(basename) {
  if (_jsLocationCache === null) {
    _jsLocationCache = new Map();
    const jsDir = path.join(ROOT, 'js');
    for (const sub of JS_SUBFOLDERS) {
      const subDir = path.join(jsDir, sub);
      if (!fs.existsSync(subDir)) continue;
      for (const f of fs.readdirSync(subDir)) {
        if (f.endsWith('.js')) _jsLocationCache.set(f, `js/${sub}/${f}`);
      }
    }
  }
  return _jsLocationCache.get(basename);
}

function readFile(rel) {
  let abs = path.join(ROOT, rel);
  if (!fs.existsSync(abs)) {
    const m = /^js\/([A-Za-z0-9_-]+\.js)$/.exec(rel);
    const resolved = m && _jsFileLocation(m[1]);
    if (resolved) abs = path.join(ROOT, resolved);
  }
  if (!fs.existsSync(abs)) {
    fail(`Source file not found: ${rel}`);
    process.exit(1);
  }
  return fs.readFileSync(abs, 'utf8');
}

// ── Rulebook read helpers (2.8.5 U-R2, the rules restructure) ────
// The rulebook is no longer one file. CLAUDE.md carries the universal
// contract; rules/*.md carry the surface-scoped subsystem notes. Any test
// asking "is rule X codified?" must look across BOTH, or the restructure
// would silently break it — the guard follows the content it guards.
function ruleNoteFiles() {
  const dir = path.join(ROOT, 'rules');
  if (!fs.existsSync(dir)) return [];
  return fs
    .readdirSync(dir)
    .filter(f => f.endsWith('.md'))
    .sort()
    .map(f => `rules/${f}`);
}

function rulebookFiles() {
  return ['CLAUDE.md', ...ruleNoteFiles()];
}

function readRulebook() {
  return rulebookFiles()
    .map(f => readFile(f))
    .join('\n');
}

// ── Logical-bundle read helper (2.8.5 U-A0) ─────────────────────
// A content-location test asserts "literal L lives somewhere in the ui-core
// FAMILY", not "literal L lives in this one exact file". readGroup(stem)
// concatenates every js/<stem>.js + js/<stem>-*.js file on disk into one
// string, so a future split (ui-core.js -> ui-core.js + ui-core-nav.js + ...)
// keeps every existing readGroup('ui-core').includes(L) assertion green
// without editing a single test — the split file just joins the group glob.
// For a stem that hasn't split yet, the family is exactly one file, so this
// returns byte-identical output to the old readFile(`js/${stem}.js`) call
// (Array.prototype.join never inserts a separator for a single-element
// array) — this migration is provably coverage-identical today.
//
// GROUP_OVERRIDES exists for the one case the plain glob can't handle: a
// split whose sibling files intentionally don't share a `<stem>-*.js`
// filename prefix (see planning/2.8.5/plans/CODE_HEALTH_PLAN.md §2.3 — the proposed
// api.js split into ai-directive.js / ai-import.js / native-router.js does
// NOT follow the stem-prefix convention §2 states as governing). Empty
// today because no file has split yet; a future split unit adds one entry
// here if it ships non-prefixed sibling names instead of renaming them to
// fit the glob.
const GROUP_OVERRIDES = {};
function readGroup(stem) {
  if (GROUP_OVERRIDES[stem]) {
    return GROUP_OVERRIDES[stem].map(f => readFile(`js/${f}`)).join('\n');
  }
  // 2.8.5 U-A2: the family now lives inside one js/<subfolder>/, not flat
  // js/ — search every subfolder (a stem's siblings always share one
  // subfolder, e.g. all six ui-core* files live in js/ui/) and sort file
  // paths so join order stays deterministic.
  const jsDir = path.join(ROOT, 'js');
  const matches = [];
  for (const sub of JS_SUBFOLDERS) {
    const subDir = path.join(jsDir, sub);
    if (!fs.existsSync(subDir)) continue;
    for (const f of fs.readdirSync(subDir)) {
      if (f === `${stem}.js` || (f.startsWith(`${stem}-`) && f.endsWith('.js'))) {
        matches.push(path.join(subDir, f));
      }
    }
  }
  matches.sort();
  if (matches.length === 0) {
    fail(`Source file family not found: js/${stem}.js (or js/${stem}-*.js)`);
    process.exit(1);
  }
  return matches.map(f => fs.readFileSync(f, 'utf8')).join('\n');
}

// ── CSS split read helper (2.8.5 U-A2) ──────────────────────────
// terminal.css was split into 12 files as a pure ordered cut (cascade is
// order-sensitive — see 99-mobile.css's own header comment on why it must
// load last). CSS_SPLIT_FILES is DERIVED from index.html's own <link> tags
// (audit N2, 2.8.5 U-A3: a hand-maintained copy here could silently drift
// from the real cascade order, since nothing cross-checked it against
// index.html — only scripts/check-boot-chain.js's CANONICAL_CSS_ORDER ever
// was). Deriving it collapses this runner's copy to zero duplication: readCss()
// always concatenates in whatever order the browser actually loads, and
// check-boot-chain.js CHECK I/J/K independently guards that index.html's own
// order is the CORRECT one (this derivation can't detect a wrong order in
// index.html itself — only reproduce it faithfully).
function _deriveCssSplitOrder() {
  const html = readFile('index.html');
  const re = /<link[^>]*\srel=["']stylesheet["'][^>]*\shref=["']css\/([A-Za-z0-9_-]+\.css)["']/g;
  const out = [];
  let m;
  while ((m = re.exec(html))) out.push(m[1]);
  if (out.length === 0) {
    fail(
      'index.html has no css/*.css <link rel="stylesheet"> tags — cannot derive CSS split order'
    );
    process.exit(1);
  }
  return out;
}
const CSS_SPLIT_FILES = _deriveCssSplitOrder();
function readCss() {
  return CSS_SPLIT_FILES.map(f => readFile(`css/${f}`)).join('\n');
}

// ── AST-lite helpers ───────────────────────────────────────────

/**
 * Extract the body of a function declaration by counting braces.
 * Works for both "function foo() {" and "= function() {" forms.
 */
function extractFunctionBody(source, fnName) {
  // Try declaration form first, then assignment form
  let idx = source.indexOf(`function ${fnName}`);
  if (idx === -1) idx = source.indexOf(`function(`); // fallback for anon (unused here)
  if (idx === -1) throw new Error(`Cannot find function "${fnName}"`);

  let i = source.indexOf('{', idx);
  if (i === -1) throw new Error(`No opening brace for "${fnName}"`);
  let depth = 0;
  const start = i;
  while (i < source.length) {
    if (source[i] === '{') depth++;
    else if (source[i] === '}' && --depth === 0) return source.slice(start, i + 1);
    i++;
  }
  throw new Error(`Unclosed brace for function "${fnName}"`);
}

// U1 (Step 2 Phase 0): getSystemDirective() was decomposed into 8 per-section
// builder functions — the AI directive TEXT now lives across all of them, not in
// getSystemDirective()'s own (now-short, composition-only) body. Any test that
// checks directive CONTENT (schema keys, tracker text, injection-resistance
// copy, etc.) must search the concatenation of every builder body, not just
// extractFunctionBody(src, 'getSystemDirective'). Tests that check
// getSystemDirective()'s own logic (ctx resolution, no-localStorage-read, call
// count) should keep using extractFunctionBody('getSystemDirective') directly.
const DIRECTIVE_BUILDER_NAMES = [
  'getSystemDirective',
  '_directiveConstraints',
  '_directivePersonaAndContract',
  '_directiveCoreTracking',
  '_directiveSkills',
  '_directiveFactions',
  '_directiveSystems',
  '_directiveTrackers',
  '_directiveInjectionBoundary',
];
function getDirectiveFullBody(src) {
  return DIRECTIVE_BUILDER_NAMES.map(n => {
    try {
      return extractFunctionBody(src, n);
    } catch (_) {
      return '';
    }
  }).join('\n');
}

// Extract a `window.NAME = [async ]function (params) { body }` assignment so it can
// be reconstructed and evaluated in isolation (the window-assigned analogue of
// extractFunctionBody). Returns { isAsync, params, body }.
function extractAssignedFunction(source, name) {
  const m = source.match(new RegExp('window\\.' + name + '\\s*=\\s*(async\\s+)?function'));
  if (!m) throw new Error(`Cannot find window.${name} = function`);
  const idx = m.index;
  const openParen = source.indexOf('(', idx);
  const openBrace = source.indexOf('{', openParen);
  let depth = 0;
  let i = openBrace;
  for (; i < source.length; i++) {
    if (source[i] === '{') depth++;
    else if (source[i] === '}' && --depth === 0) {
      i++;
      break;
    }
  }
  return {
    isAsync: !!m[1],
    params: source.slice(openParen, openBrace).trim(),
    body: source.slice(openBrace, i),
  };
}

/**
 * Extract top-level keys from "let state = { ... };" using brace-depth tracking.
 * Handles multi-key lines, nested objects (skills, factions), and arrays.
 *
 * This is the auto-discovery engine. Adding a new field to state will
 * automatically appear in the results — no manual list to maintain.
 */
function extractStateKeys(source) {
  const startM = source.match(/let state\s*=\s*\{/);
  if (!startM) throw new Error('Cannot find "let state = {" in state.js');

  // Walk from the opening '{' and collect depth-0 identifier keys
  let i = startM.index + startM[0].length - 1; // index of '{'
  let depth = 0;
  const keys = [];
  const re = /(\{|\[|\}|\])|(\b[a-zA-Z_]\w*)\s*:/g;

  // Advance re to the correct offset inside the string
  re.lastIndex = i;
  let m;
  while ((m = re.exec(source)) !== null) {
    const bracket = m[1],
      keyName = m[2];
    if (bracket === '{' || bracket === '[') {
      depth++;
      continue;
    }
    if (bracket === '}' || bracket === ']') {
      if (--depth === 0) break;
      continue;
    }
    if (keyName && depth === 1) keys.push(keyName); // depth 1 = inside outer { }
  }
  return [...new Set(keys)];
}

/** Pull all { key: '...' } strings from FACTION_REGISTRY. */
function extractFactionKeys(source) {
  const m = source.match(/const FACTION_REGISTRY\s*=\s*\[([^]*?)\];/);
  if (!m) throw new Error('Cannot find FACTION_REGISTRY in state.js');
  return [...m[1].matchAll(/key:\s*'([^']+)'/g)].map(x => x[1]);
}

/** Pull all quoted strings from SKILL_KEYS array. */
function extractSkillKeys(source) {
  const m = source.match(/const SKILL_KEYS\s*=\s*\[([^\]]+)\]/);
  if (!m) throw new Error('Cannot find SKILL_KEYS in state.js');
  return [...m[1].matchAll(/'([^']+)'/g)].map(x => x[1]);
}

// ══════════════════════════════════════════════════════════════
//  LOAD SOURCES
// ══════════════════════════════════════════════════════════════
const stateSource = readGroup('state');
const apiSource = readGroup('api');
const cloudSource = readGroup('cloud');
const uiSource = ['js/ui-audio.js', 'js/ui-saves.js', 'js/ui-account.js']
  .filter(f => {
    if (fs.existsSync(path.join(ROOT, f))) return true;
    const m = /^js\/([A-Za-z0-9_-]+\.js)$/.exec(f);
    return !!(m && _jsFileLocation(m[1]));
  })
  .map(f => readFile(f))
  .concat([readGroup('ui-core'), readGroup('ui-render')]) // 2.8.5 U-A1/U-A4: ui-core.js + its
  // ui-core-*.js split family, and ui-render.js + its ui-render-*.js split family
  .join('\n');

console.log('\n══ RobCo Persistence Audit ════════════════════════════════════\n');

// ── Discover schema ────────────────────────────────────────────
let stateKeys, factionKeys, skillKeys, importBody;
try {
  stateKeys = extractStateKeys(stateSource);
  factionKeys = extractFactionKeys(stateSource);
  skillKeys = extractSkillKeys(stateSource);
  importBody = extractFunctionBody(apiSource, 'autoImportState');
} catch (e) {
  console.error(red(`FATAL — parser error: ${e.message}`));
  process.exit(1);
}

console.log(`  Auto-discovered ${stateKeys.length} top-level state keys:`);
console.log(dim(`  [ ${stateKeys.join(', ')} ]`));
console.log(`  ${factionKeys.length} faction keys  |  ${skillKeys.length} skill keys\n`);

// ══════════════════════════════════════════════════════════════
//  SUITE 0 — Parser sanity (guards against regex regression)
//  If this suite fails, the test itself is broken, not your code.
// ══════════════════════════════════════════════════════════════
header('Parser sanity');
const KNOWN_KEYS = [
  'lvl',
  'xp',
  'hpCur',
  'hpMax',
  's',
  'p',
  'e',
  'c',
  'i',
  'a',
  'l',
  'caps',
  'loc',
  'rads',
  'karma',
  'ticks',
  'la',
  'ra',
  'll',
  'rl',
  'hd',
  'factions',
  'skills',
  'status',
  'inventory',
  'squad',
  'campaign_notes',
];
for (const k of KNOWN_KEYS) {
  assert(stateKeys.includes(k), `Parser found known key: state.${k}`);
}

// ══════════════════════════════════════════════════════════════
//  SUITE 1 — Every state key is referenced in autoImportState()
//  This is the core auto-discovery suite.
//  Adding a new key to `state` and NOT wiring it here → FAIL.
// ══════════════════════════════════════════════════════════════
header('autoImportState() field coverage  ← core auto-discovery');
for (const key of stateKeys) {
  // Case-insensitive word-boundary search covers:
  //   flat.hpcur  (lowercase from the flatten() step)
  //   parsed.factions, parsed.skills, parsed.inventory, etc.
  //   'la','ra','ll','rl','hd'  (string array literals)
  //   's','p','e','c','i','a','l'  (string array literals)
  const found = new RegExp(`\\b${key}\\b`, 'i').test(importBody);
  assert(found, `state.${key}`);
}

// ══════════════════════════════════════════════════════════════
//  SUITE 2 — FACTION_REGISTRY completeness
// ══════════════════════════════════════════════════════════════
header('FACTION_REGISTRY completeness');
const EXPECTED_FACTIONS = [
  // Major (6)
  'ncr',
  'legion',
  'house',
  'bos',
  'boomers',
  'khans',
  // Minor (5)
  'followers',
  'powder',
  'kings',
  'strip',
  'freeside',
];
for (const key of EXPECTED_FACTIONS) {
  assert(factionKeys.includes(key), `FACTION_REGISTRY key: "${key}"`);
}
assert(
  (/FACTION_REGISTRY\.forEach/.test(importBody) ||
    /getFactionRegistry\(\)\.forEach/.test(importBody)) &&
    /parsed\.factions/.test(importBody),
  'autoImportState() imports all factions via FACTION_REGISTRY.forEach'
);
assert(
  factionKeys.length === EXPECTED_FACTIONS.length,
  `FACTION_REGISTRY has exactly ${EXPECTED_FACTIONS.length} factions (${factionKeys.length} found)`
);

// ══════════════════════════════════════════════════════════════
//  SUITE 2b — Reputation 2D Matrix (C1)
//  Verifies getFactionStanding() produces canonical FNV titles.
//  Runs FACTION_THRESHOLDS + getFactionStanding in an isolated vm.
// ══════════════════════════════════════════════════════════════
header('Reputation 2D Matrix');
try {
  const vm = require('vm');

  // Extract FACTION_THRESHOLDS block and getFactionStanding from ui.js source
  const threshMatch = uiSource.match(/const FACTION_THRESHOLDS\s*=\s*\{[\s\S]*?\};\s*\/\/ Default/);
  const defaultMatch = uiSource.match(/const _DEFAULT_THRESHOLDS\s*=\s*\{[^}]+\};/);
  const fnMatch = uiSource.match(/function getFactionStanding\([\s\S]*?\n\}/);

  if (!threshMatch || !defaultMatch || !fnMatch) {
    fail('Could not extract FACTION_THRESHOLDS or getFactionStanding from ui.js');
  } else {
    const sandboxCode = `${threshMatch[0]}\n${defaultMatch[0]}\n${fnMatch[0]}`;
    const sandbox = {};
    vm.createContext(sandbox);
    vm.runInContext(sandboxCode, sandbox);
    const gfs = sandbox.getFactionStanding;

    // NCR: max fame (100), no infamy → Idolized
    assert(
      gfs('ncr', 100, 0).label === 'Idolized',
      "getFactionStanding('ncr', 100, 0) returns 'Idolized'"
    );
    // BOS: fame=20 (at t4), infamy=0 → Idolized (BOS t4=20)
    assert(
      gfs('bos', 20, 0).label === 'Idolized',
      "getFactionStanding('bos', 20, 0) returns 'Idolized'"
    );
    // BOS: fame=20 (t4), infamy=20 (t4) → Wild Child
    assert(
      gfs('bos', 20, 20).label === 'Wild Child',
      "getFactionStanding('bos', 20, 20) returns 'Wild Child'"
    );
    // NCR: fame=50 (fr3: 40≤50<80), infamy=20 (ir2: 12≤20<40) → Smiling Troublemaker
    assert(
      gfs('ncr', 50, 20).label === 'Smiling Troublemaker',
      "getFactionStanding('ncr', 50, 20) returns 'Smiling Troublemaker'"
    );
    // NCR: fame=0, infamy=30 (t3=ir2) → Shunned (fr=0, ir=2)
    assert(
      gfs('ncr', 0, 30).label === 'Shunned',
      "getFactionStanding('ncr', 0, 30) returns 'Shunned'"
    );
    // NCR: fame=80 (fr4: ≥bp3=80), infamy=20 (ir2: 12≤20<40) → Good-Natured Rascal
    assert(
      gfs('ncr', 80, 20).label === 'Good-Natured Rascal',
      "getFactionStanding('ncr', 80, 20) returns 'Good-Natured Rascal'"
    );
    // NCR: fame=0, infamy=50 (t3=ir3) → Hated (fr=0, ir=3)
    assert(gfs('ncr', 0, 50).label === 'Hated', "getFactionStanding('ncr', 0, 50) returns 'Hated'");
    // NCR: fame=0, infamy=0 → Neutral
    assert(
      gfs('ncr', 0, 0).label === 'Neutral',
      "getFactionStanding('ncr', 0, 0) returns 'Neutral'"
    );
    // NCR: fame=0, infamy=80 (t4) → Vilified
    assert(
      gfs('ncr', 0, 80).label === 'Vilified',
      "getFactionStanding('ncr', 0, 80) returns 'Vilified'"
    );
  }
} catch (e) {
  fail(`Reputation 2D Matrix runtime test failed: ${e.message}`);
}

// ══════════════════════════════════════════════════════════════
//  SUITE 2c — C2 CRUD Functions (C2)
