        'state-add-companion',
        'state-max-affinity',
        'state-clear-squad',
        'state-set-time-of-day',
        'state-advance-time',
        'state-preset-max-everything',
        'state-preset-fresh-start',
        'state-preset-low-hp',
        'state-preset-crippled',
