        'reset-first-run',
        'reset-firmware-seen',
        'reset-hatch-flag',
        'reset-greet-flag',
        'reset-error-log',
        'reset-device-prefs',
        'reset-bezel-view',
        'reset-map-fog',
        'reset-quests',
        'reset-inventory',
